function makeLessonTitles(titles: string[]): Record<string, string[]> {
  const result: Record<string, string[]> = {};
  for (const langKey of ['english', 'french', 'spanish', 'russian', 'german']) {
    result[langKey] = titles;
  }
  return result;
}
